	// maxExecutionTime is the maximum time allowed for Lua script execution
	maxExecutionTime = 5 * time.Second
	// maxMemory is the maximum memory (in bytes) allowed for the Lua VM
	maxMemory = 1024 * 1024 // 1MB
	// maxCallStackSize is the maximum depth of the Lua call stack
	maxCallStackSize = 256
	// maxScriptSize is the maximum size of the Lua script in bytes
	maxScriptSize = 64 * 1024 // 64KB
	// maxContextSize is the maximum number of entries in the context map
	maxContextSize = 100
)

