// of a product based on the given context.
// The script must define a function named 'calculate_final_price' that takes a context
// table and returns a number.
//
// Security measures implemented:
//   - Memory and call stack limits prevent resource exhaustion attacks
//   - Execution timeout prevents infinite loops and long-running scripts
//   - Only safe Lua libraries are loaded (no os, io, debug, or package)
//   - Dangerous functions (loadfile, dofile, loadstring, etc.) are removed from global scope
//   - Input size limits prevent excessively large scripts or context data
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Validate script size to prevent memory exhaustion attacks
	if len(script) > maxScriptSize {
		return 0, fmt.Errorf("script size exceeds maximum allowed size of %d bytes", maxScriptSize)
	}

	// Validate context size to prevent memory exhaustion
	if len(ctx) > maxContextSize {
		return 0, fmt.Errorf("context size exceeds maximum allowed size of %d entries", maxContextSize)
	}

	// Create a context with timeout to prevent infinite loops or long-running scripts
	execCtx, cancel := context.WithTimeout(context.Background(), maxExecutionTime)
	defer cancel()

	// Create a new Lua state with security restrictions
	L := lua.NewState(lua.Options{
		SkipOpenLibs:    true,             // Don't load any libraries by default
		RegistryMaxSize: maxMemory,        // Limit memory usage to prevent OOM
		CallStackSize:   maxCallStackSize, // Limit call stack depth to prevent stack overflow
	})
	defer L.Close()

	// Set context for cancellation support (allows interruption on timeout)
	L.SetContext(execCtx)

	// Open only safe libraries (exclude os, io, debug, package which are dangerous)
	lua.OpenBase(L)   // Basic functions (we'll remove dangerous ones below)
	lua.OpenMath(L)   // Math functions - safe
	lua.OpenString(L) // String manipulation - safe
	lua.OpenTable(L)  // Table manipulation - safe

	// Remove dangerous functions from the global environment
	// These functions could be used to escape the sandbox or cause harm
	dangerousFuncs := []string{
		"dofile",         // Can load and execute arbitrary files
		"loadfile",       // Can load arbitrary files
		"loadstring",     // Can compile and execute arbitrary code strings
		"load",           // Similar to loadstring (Lua 5.2+)
		"module",         // Can modify module system
		"require",        // Can load external modules
		"getfenv",        // Can access function environments (Lua 5.1)
		"setfenv",        // Can modify function environments (Lua 5.1)
		"collectgarbage", // Can interfere with garbage collector
		"print",          // Not dangerous, but unnecessary in production
	}
	for _, fn := range dangerousFuncs {
		L.SetGlobal(fn, lua.LNil)
	}

	// Load and execute the user-provided script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute script: %w", err)
	}

	// Check if the required function exists
	calcFn := L.GetGlobal("calculate_final_price")
	if calcFn == lua.LNil {
		return 0, fmt.Errorf("script must define a function named 'calculate_final_price'")
	}

	// Create the context table to pass to the Lua function
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the calculate_final_price function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      calcFn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the return value
	ret := L.Get(-1)
	L.Pop(1) // Remove the return value from the stack

	// Validate the return type
	result, ok := ret.(lua.LNumber)
	if !ok {
		return 0, fmt.Errorf("calculate_final_price must return a number, got %s", ret.Type())
	}

