func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state with restricted capabilities
	// SkipOpenLibs prevents automatic loading of all standard libraries
	L := lua.NewState(lua.Options{
		SkipOpenLibs: true,
	})
	defer L.Close()

	// Open only safe libraries needed for pricing calculations
	// NOT loaded: os, io, debug, package, coroutine
	lua.OpenBase(L)
	lua.OpenMath(L)
	lua.OpenString(L)
	lua.OpenTable(L)

	// Remove dangerous functions from the global environment
	// These could be used to escape the sandbox or access the filesystem
	dangerousFuncs := []string{
		"dofile",     // Can execute arbitrary files
		"loadfile",   // Can load arbitrary files
		"load",       // Can compile arbitrary code strings
		"loadstring", // Alias for load in Lua 5.1
		"require",    // Can load external modules
	}
	for _, fn := range dangerousFuncs {
		L.SetGlobal(fn, lua.LNil)
	}

	// Set memory limit to prevent excessive memory consumption
	L.SetMx(maxMemoryMB * 1024 * 1024)

	// Load and execute the script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope
