	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result from the Lua stack
	result := L.Get(-1)
	L.Pop(1) // Remove the result from the stack

	// Convert result to float64
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

