package main

import (
	"errors"
	"fmt"

	"github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a Lua script to calculate the final price of a product.
// The script must define a global function named 'calculate_final_price' that takes
// a context table and returns a number.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state
	L := lua.NewState()
	defer L.Close()

	// Execute the script to define the calculate_final_price function
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute script: %w", err)
	}

	// Get the calculate_final_price function from global scope
	calcFunc := L.GetGlobal("calculate_final_price")
	if calcFunc == lua.LNil {
		return 0, errors.New("calculate_final_price function not found in script")
	}

	// Ensure it's a function
	if calcFunc.Type() != lua.LTFunction {
		return 0, errors.New("calculate_final_price is not a function")
	}

	// Create a Lua table from the context map
	ctxTable := L.NewTable()
	for key, value := range ctx {
		L.SetField(ctxTable, key, lua.LNumber(value))
	}

	// Call the calculate_final_price function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      calcFunc,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the return value from the stack
	ret := L.Get(-1)
	L.Pop(1) // Clean up the stack

	// Convert to float64
	if num, ok := ret.(lua.LNumber); ok {
		return float64(num), nil
	}

	return 0, errors.New("calculate_final_price did not return a number")
}

func main() {
	// Example Lua script for pricing
	script := `
function calculate_final_price(ctx)
    -- Apply 10% discount for VIP users (tier 2)
    if ctx.user_tier >= 2 then
        return ctx.base_price * 0.9
    else
        return ctx.base_price
    end
end
`

	// Test case 1: VIP user (tier 2) - should get 10% discount
	ctx1 := map[string]float64{
		"base_price": 100.0,
		"user_tier":  2.0,
	}
	result1, err := ExecutePricingScript(script, ctx1)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Printf("VIP user price: %.2f (expected: 90.00)\n", result1)
	}

	// Test case 2: Regular user (tier 1) - no discount
	ctx2 := map[string]float64{
		"base_price": 100.0,
		"user_tier":  1.0,
	}
	result2, err := ExecutePricingScript(script, ctx2)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Printf("Regular user price: %.2f (expected: 100.00)\n", result2)
	}

	// Test case 3: Premium VIP user (tier 3) with higher base price
	ctx3 := map[string]float64{
		"base_price": 250.0,
		"user_tier":  3.0,
	}
	result3, err := ExecutePricingScript(script, ctx3)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Printf("Premium VIP price: %.2f (expected: 225.00)\n", result3)
	}
}

